package org.example.matrix.config;

import org.apache.sling.caconfig.annotation.Configuration;
import org.apache.sling.caconfig.annotation.Property;

@Configuration(label = "Matrix Settings", description = "Configure the Matrix parameters")
public @interface MatrixConfiguration {

    @Property(label = "Digital Rain Speed", description = "Speed of falling code")
    int digitalRainSpeed() default 100;

    @Property(label = "Enable Red Pill", description = "Allow users to see the truth")
    boolean enableRedPill() default false;

    @Property(label = "Reality Level", description = "Depth of simulation")
    String realityLevel() default "surface";

    @Property(label = "Authorized Agents")
    String[] authorizedAgents() default {"Neo", "Trinity", "Morpheus"};
}

// Using the configuration
import org.apache.sling.api.resource.Resource;
import org.apache.sling.caconfig.ConfigurationBuilder;

public class MatrixService {

    public void configureMatrix(Resource resource) {
        MatrixConfiguration config = resource.adaptTo(ConfigurationBuilder.class)
            .as(MatrixConfiguration.class);

        int speed = config.digitalRainSpeed();
        boolean canSeeTruth = config.enableRedPill();
    }
}
